  "std:fmt": "// `std:fmt` — pure-VL formatting helpers over the intrinsic floor\n// (docs/std-design.md D4 item 1). Imports nothing: strings are built with\n// `+`/`.slice` and rendered digit by digit. f64→string (shortest round-trip,\n// Ryu-class) is deliberately absent — `print` keeps covering floats.\n\n// Decimal digit d in 0..=9 as its character. Takes i64 so both integer\n// widths share one renderer (i64 cannot narrow to i32, so a string-index\n// lookup is not expressible for the wide path).\nfunction digitChar(d: i64): string {\n  if d == 0 { return \"0\" }\n  if d == 1 { return \"1\" }\n  if d == 2 { return \"2\" }\n  if d == 3 { return \"3\" }\n  if d == 4 { return \"4\" }\n  if d == 5 { return \"5\" }\n  if d == 6 { return \"6\" }\n  if d == 7 { return \"7\" }\n  if d == 8 { return \"8\" }\n  \"9\"\n}\n\n// Decimal rendering of any i64, including i64 min. The accumulator works in\n// the NEGATIVE range (positive inputs are negated first) because the negative\n// range covers i64 min, whose magnitude overflows when negated; `%` on a\n// negative operand yields a digit in -9..=0, negated back per digit.\nexport function i64ToStr(n: i64): string {\n  if n == 0 { return \"0\" }\n  const zero: i64 = 0\n  let m: i64 = n\n  if m > 0 { m = zero - m }\n  let out = \"\"\n  while m < 0 {\n    out = digitChar(zero - (m % 10)) + out\n    m = m / 10\n  }\n  if n < 0 { out = \"-\" + out }\n  out\n}\n\n// Decimal rendering of any i32, including i32 min (widening into the i64\n// renderer preserves the value exactly).\nexport function toStr(n: i32): string {\n  const wide: i64 = n\n  return i64ToStr(wide)\n}\n\nexport function boolToStr(b: boolean): string {\n  if b { return \"true\" }\n  \"false\"\n}\n\n// `s` concatenated n times; n <= 0 yields \"\".\nexport function repeat(s: string, n: i32): string {\n  let out = \"\"\n  let i = 0\n  while i < n {\n    out = out + s\n    i = i + 1\n  }\n  out\n}\n\n// Pads `s` on the left with `fill` up to `width`. A multi-codepoint fill is\n// tiled and truncated so the result is exactly `width` long; returns `s`\n// unchanged when it is already wide enough or when fill is empty.\nexport function padLeft(s: string, width: i32, fill: string): string {\n  if fill.length == 0 { return s }\n  const deficit = width - s.length\n  if deficit <= 0 { return s }\n  let pad = \"\"\n  let have = 0\n  while have < deficit {\n    pad = pad + fill\n    have = have + fill.length\n  }\n  return pad.slice(0, deficit) + s\n}\n\n// Elements of `parts` concatenated with `sep` between consecutive elements.\nexport function join(parts: string[], sep: string): string {\n  let out = \"\"\n  let i = 0\n  while i < parts.length {\n    if i > 0 { out = out + sep }\n    out = out + parts[i]\n    i = i + 1\n  }\n  out\n}\n",
